StructuredTextModel.Text:
A := (Pitman_Length+Half_Stroke-Distance_From_BDC);
Square_Pitman_Length := EXPT(Pitman_Length, 2);
Square_Half_Stroke := EXPT(Half_Stroke, 2);
Square_A := EXPT(A, 2);

BDC_To_Deg := 180-RadToDeg(ACOS((Square_Pitman_Length-Square_Half_Stroke-Square_A)/(-2*Half_Stroke*A)));
